// Parse de las 2 vistas:
//  - Atendidos esperando respuesta: filas con updated_by_type = 'Usuario final'
//  - Sin atender: todas las filas de la vista 'Sin leer'
const waitingBody    = $('ZD View Atendidos').first().json   || {};
const unattendedBody = $input.first().json                   || {};

const waitingRows    = Array.isArray(waitingBody.rows)    ? waitingBody.rows    : [];
const unattendedRows = Array.isArray(unattendedBody.rows) ? unattendedBody.rows : [];

function mapRow(r) {
  const ru = r.requester_updated_at || null;
  const sinceLastDays = ru ? Math.floor((Date.now() - new Date(ru).getTime()) / 86400000) : null;
  return {
    ticket_id: r.ticket_id,
    subject: r.subject || '(sin asunto)',
    days_since_user_updated: sinceLastDays,
    last_user_update_at: ru,
    updated_by_type: r.updated_by_type || null,
    url: `https://soporteyurest.zendesk.com/agent/tickets/${r.ticket_id}`
  };
}

const needs = waitingRows
  .filter(r => r && r.ticket_id && r.updated_by_type === 'Usuario final')
  .map(mapRow)
  .sort((a,b) => (a.days_since_user_updated ?? 999) - (b.days_since_user_updated ?? 999));

const unattended = unattendedRows
  .filter(r => r && r.ticket_id)
  .map(mapRow)
  .sort((a,b) => (a.days_since_user_updated ?? 999) - (b.days_since_user_updated ?? 999));

return [{ json: {
  generated_at: new Date().toISOString(),
  // Atendidos esperando respuesta (lógica anterior; mantenemos el nombre del campo
  // por compatibilidad con el frontend existente).
  needs_agent_reply_count: needs.length,
  needs_agent_reply_ids_csv: needs.map(n => n.ticket_id).join(','),
  needs_agent_reply: needs,
  // Sin atender (nuevo)
  unattended_count: unattended.length,
  unattended_ids_csv: unattended.map(n => n.ticket_id).join(','),
  unattended: unattended,
  // Diagnóstico
  view_waiting_total_rows:    waitingRows.length,
  view_unattended_total_rows: unattendedRows.length
} }];
